// This will collect all logs into a single array of strings
const logs = items.map(item => item.json.log);
return [{ json: { file: logs.join('\n') } }];

const lokiUrl = 'http://localhost:3100/loki/api/v1/query_range';
const query = '{job=~".+"}';
const now = Date.now();
const startTime = (now - 3 * 60 * 60 * 1000) * 1000000; // 3 hours ago, in nanoseconds
const endTime = now * 1000000; // now, in nanoseconds

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: lokiUrl,
  qs: {
    query,
    start: startTime,
    end: endTime,
    limit: 1000,
  },
});

return { json: response };

// n8n Function node code
// Formats previous_node.json data to test.log style

const output = [];

for (const item of items) {
  const results = item.json.data.result;
  for (const result of results) {
    const values = result.values;
    for (const value of values) {
      // value[1] is the log message
      output.push({
        json: {
          log: value[1]
        }
      });
    }
  }
}

return output;

// Generate fallback anomaly data when the API is not available or fails
// This simulates a situation where port 8000 is closed by the Fedora firewall

// Check if the API call failed or returned no data
const apiResponse = $input.item.json;
let useGeneratedData = true;

// If we have valid API response data, don't generate fallback
if (apiResponse && apiResponse.body && apiResponse.body.anomalies && 
    Array.isArray(apiResponse.body.anomalies) && apiResponse.body.anomalies.length > 0) {
  useGeneratedData = false;
}

// If status code indicates failure, generate fallback
if (apiResponse && apiResponse.statusCode >= 400) {
  useGeneratedData = true;
}

// Generate dummy anomaly data
if (useGeneratedData) {
  // Current timestamp
  const timestamp = new Date().toISOString();

  // Create simulated log entries for port 8000 blocked by Fedora firewall
  const simulatedLogs = [
    `${timestamp} monitored-node-01 kernel: [143245.342] firewalld[3456]: ERROR: Connection to port 8000 blocked by firewall policy`,
    `${timestamp} monitored-node-01 systemd[1]: FAILED to start service on port 8000: Connection refused`,
    `${timestamp} monitored-node-01 lustre-service[2345]: ERROR: Cannot establish connection to client on port 8000`,
    `${timestamp} monitored-node-01 kernel: [143245.567] firewalld[3456]: Port 8000/tcp is closed by zone 'public'`,
    `${timestamp} monitored-node-01 app-server[8765]: FATAL: Unable to bind to port 8000: Permission denied (SELINUX may be blocking)`,
    `${timestamp} monitored-node-01 application[9876]: Connection to localhost:8000 failed - ECONNREFUSED`,
    `${timestamp} monitored-node-01 audit: SYSCALL arch=c000003e syscall=socket success=no exit=-13 ppid=1254 pid=1255 auid=1000 uid=1000 comm=\"application\" reason=\"port 8000 blocked by firewalld\"`
  ];

  // Format response to match what Process Anomaly Results expects
  return {
    json: {
      body: {
        anomalies: simulatedLogs.map(log => ({
          content: log,
          score: 0.92,
          type: "firewall_block"
        }))
      },
      statusCode: 200
    }
  };
} else {
  // If real API provided results, pass them through
  return $input.item;
}

// Main function to process anomaly detection results
// Extract the response data from the API call
let anomalyEntries = [];

// Handle the specific data structure you're receiving
if ($input.item.json && Array.isArray($input.item.json) && $input.item.json.length > 0) {
  // Check if anomalies are nested in body.anomalies
  const firstItem = $input.item.json[0];

  if (firstItem.body && firstItem.body.anomalies && Array.isArray(firstItem.body.anomalies)) {
    // Extract anomalies from the nested structure
    anomalyEntries = firstItem.body.anomalies;
  }
}

// If no anomaly entries found using the above method, try other possible structures
if (anomalyEntries.length === 0) {
  // Try other possible data structures
  if ($input.item.json.body && $input.item.json.body.anomalies) {
    anomalyEntries = $input.item.json.body.anomalies;
  } else if ($input.item.json.anomalies) {
    anomalyEntries = $input.item.json.anomalies;
  }
}

// Extract log content from anomaly entries
const logEntries = anomalyEntries.map(item => item.content || '').filter(Boolean);

// Count the number of serious errors
const fatalErrorCount = logEntries.filter(log => 
  log.includes('FATAL') || log.includes('ERROR') || log.includes('FAILED')
).length;

// Extract server information from log entries
const serverInfo = extractServerInfoFromLogs(logEntries);

// Determine severity based on error count - with fixed thresholds
let severity = 'low';
if (fatalErrorCount >= 1) {
  severity = 'high';  // Any FATAL errors should be high severity
} else if (logEntries.length >= 5) {
  severity = 'medium';
}

// Calculate an appropriate anomaly score (0.0-1.0)
const anomalyScore = fatalErrorCount > 0 ? 
  Math.min(0.7 + (fatalErrorCount / 10) * 0.3, 1.0) : 
  (logEntries.length > 0 ? 0.6 : 0.1);

// Identify affected components based on log entries
const affectedComponents = identifyAffectedComponents(logEntries);

// Get current timestamp
const timestamp = new Date().toISOString();

// Build the result object with all required fields for next steps
const result = {
  serverInfo: {
    id: serverInfo.id || 'server-cluster',
    name: serverInfo.name || 'lustre-server',
    ip: serverInfo.ip 
  },
  timestamp: timestamp,
  anomalyResult: fatalErrorCount > 0 || logEntries.length > 0,
  anomalyScore: anomalyScore,
  anomalyDetails: logEntries.map(log => ({ message: log })),
  severity: severity,
  affectedComponents: affectedComponents,
  rawLogs: logEntries.slice(0, 10)
};

// Helper function to extract server information from logs
function extractServerInfoFromLogs(logs) {
  const info = {
    id: '',
    name: '',
    ip: ''
  };

  for (const log of logs) {
    if (!log || typeof log !== 'string') continue;

    // Extract node ID (like R31-M0-NC-I:J18-U11)
    const nodeIdMatch = log.match(/\b(R\d+-M\d+-N[A-Z0-9]+-I:J\d+-U\d+)\b/);
    if (!info.id && nodeIdMatch && nodeIdMatch[1]) {
      info.id = nodeIdMatch[1];
    }

    // Extract server name (like bglio513)
    const serverNameMatch = log.match(/\b(bglio\d+)\b/);
    if (!info.name && serverNameMatch && serverNameMatch[1]) {
      info.name = serverNameMatch[1];
    } else if (!info.name && log.includes('idoproxy')) {
      // For logs about idoproxy
      info.name = 'idoproxy-server';
    } else if (!info.name && (log.includes('monitored-node') || log.includes('firewalld'))) {
      // Extract monitored-node-XX from logs
      const monitoredNodeMatch = log.match(/\b(monitored-node-\d+)\b/);
      if (monitoredNodeMatch && monitoredNodeMatch[1]) {
        info.name = monitoredNodeMatch[1];
      } else {
        info.name = 'monitored-node-01'; // Default if not found
      }
    }
  }

  // Generate IP based on server name if possible
  if (!info.ip && info.name) {
    if (info.name.includes('bglio')) {
      const serverNumber = parseInt(info.name.replace(/\D/g, '')) || 1;
      info.ip = `10.1.${Math.floor(serverNumber / 255) % 255}.${serverNumber % 255}`;
    } else if (info.name.includes('monitored-node')) {
      const nodeNumber = parseInt(info.name.replace(/\D/g, '')) || 1;
      info.ip = `192.168.100.${200 + nodeNumber}`;
    } else {
      // Fallback IP for other server types
      info.ip = '10.0.1.1';
    }
  }

  return info;
}

// Helper function to identify affected components from logs
function identifyAffectedComponents(logs) {
  const components = new Set();

  for (const log of logs) {
    if (!log || typeof log !== 'string') continue;

    // Identify component based on log content
    if (log.includes('Lustre') || log.includes('lustre')) components.add('Lustre');
    if (log.includes('KERNEL') || log.includes('kernel')) components.add('Kernel');
    if (log.includes('mount')) components.add('Filesystem');
    if (log.includes('socket') || log.includes('communication')) components.add('Network');
    if (log.includes('idoproxy')) components.add('IDoProxy Service');
    if (log.includes('firewalld') || log.includes('port 8000')) components.add('Firewall');
    if (log.includes('SELINUX')) components.add('SELinux');
  }

  // Return array of components or default if none identified
  const componentList = Array.from(components);
  return componentList.length > 0 ? componentList : ['System'];
}

// Return the processed result
return { json: result };
